insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('e8ae7a02-26f1-4cdc-b4de-5da118f5dc40', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$inleiding — verven met superkritisch CO₂ (DyeCoo)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context1.png$$,
   $$Om textiel te verven, worden pigmenten gebruikt die slecht in water oplossen. Deze pigmenten zijn apolaire vaste stoffen die zich tijdens het verven hechten aan het oppervlak van de textielvezels. Met een vezel wordt in deze opgave een bundel polymeerketens bedoeld. Omdat het verven plaatsvindt in water, worden emulgatoren gebruikt om de pigmenten te mengen met het water. Na afloop van het verven komen deze milieubelastende emulgatoren in het afvalwater terecht. Het Nederlandse bedrijf DyeCoo heeft een verftechniek ontwikkeld waarbij geen afvalwater vrijkomt. In het proces wordt superkritisch CO₂ gebruikt als oplosmiddel. Superkritisch CO₂ is CO₂ dat bij T = 120 °C is samengeperst tot p = 300 bar. In deze opgave mag je aannemen dat het CO₂ zich dan als een vloeistof gedraagt. Het superkritisch CO₂ is ook apolair, zodat de pigmenten in superkritisch CO₂ oplossen zonder gebruik van emulgatoren.$$, 'inline'),
  ('a270daa1-ec47-48f8-8082-ebac02c4ef7c', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$opzwellen van polyester door CO₂$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context2.png$$,
   $$De verftechniek van DyeCoo is vooral geschikt voor het verven van polyester kledingmateriaal. Als het CO₂ in contact komt met polyester, zwellen de vezels op. Dit komt doordat de CO₂-moleculen tussen de apolaire polymeerketens dringen. Een gevolg van het opzwellen is dat een sterkere kleuring van polyester kan worden verkregen dan met de op water gebaseerde verfmethode.$$, 'inline'),
  ('fab079fd-d30a-4bce-a1b3-c0dd9f2ad52e', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$scheiden van CO₂ en pigment na het verven$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context3.png$$,
   $$Wanneer het polyester enige tijd is behandeld met de pigment-oplossing, wordt het polyester gescheiden van de pigment-oplossing. Het mengsel van superkritisch CO₂ en het overgebleven pigment wordt gescheiden, zodat het pigment kan worden hergebruikt.$$, 'inline'),
  ('a7f3d408-824e-46f3-b8b0-546f8a603b43', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$vorming en reactie van reactief pigment met katoen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context4.png$$,
   $$Het proces van DyeCoo is met een aantal aanpassingen ook te gebruiken voor katoen. Het katoen wordt dan voorbehandeld met een oplossing van methanol in superkritisch CO₂. Hierdoor zwelt het katoen op. Daarna wordt een stroom superkritisch CO₂ met een zogeheten reactief pigment doorgeleid. Een reactief pigment wordt gevormd door een geschikt pigment te laten reageren met dichloortriazine. Het gevormde reactieve pigment reageert vervolgens met het katoen. Deze reactie is op de uitwerkbijlage schematisch en onvolledig weergegeven. De reactie van het reactieve pigment met katoen is een substitutiereactie. Het O-atoom van een OH-groep van katoen valt als nucleofiel aan op één van de twee C-atomen waaraan een Cl-atoom is gebonden.$$, 'inline'),
  ('941fa3ae-da25-495f-a65b-eea2c49d8e91', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$reactief pigment in ondermaat; invloed van methanol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context5.png$$,
   $$Het reactieve pigment wordt in ondermaat toegevoegd ten opzichte van de OH-groepen in het katoen. Wanneer methanol ook tijdens het verven wordt bijgemengd, blijkt dat het percentage pigmentmoleculen dat aan het katoen is gebonden, terugloopt.$$, 'inline'),
  ('2307f327-cd94-4b78-9f96-c0a3e2ee9959', '951d189e-38e8-4efa-87c1-c678d2f478f0', $$uitwerkbijlage vraag 4 — reactie reactief pigment met cellulose-eenheid$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-groene-verf-context6.png$$,
   $$Onvolledig weergegeven reactievergelijking: reactief pigment (een 1,3,5-triazinering met een R–NH-groep en twee Cl-atomen) reageert met een cellulose-eenheid in katoen (met een CH₂OH-groep en OH-groepen). Na de pijl moet het reactieproduct nog worden getekend.$$, 'uitwerkbijlage'),
  ('d8a50b65-22e6-4d9b-99c6-a9ffcb6f45c4', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$inleiding — chloropreen en structuurformule$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context1.png$$,
   $$Chloropreen is de beginstof voor de productie van neopreen. Neopreen is een synthetisch rubber. De structuurformule van chloropreen (H₂C=CH–CCl=CH₂, oftewel 2-chloorbuta-1,3-dieen) is hiernaast weergegeven. Chloropreen wordt in een aantal stappen gemaakt. De eerste stap is de additiereactie van buta-1,3-dieen met chloor. Daarbij ontstaat onder andere 3,4-dichloorbut-1-een (3,4-DCB). Het mechanisme voor de vorming van 3,4-DCB is weergegeven in mechanisme 1.$$, 'inline'),
  ('3976955d-dc9c-4f09-8d77-d6e40bc15778', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$mechanisme 1 — vorming van 3,4-DCB via een chlorinium-ion$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context2.png$$,
   $$mechanisme 1: stap 1 — buta-1,3-dieen reageert met Cl₂, waarbij een cyclisch chlorinium-ion en een Cl⁻-ion ontstaan. stap 2 — het chlorinium-ion reageert met het vrijgekomen Cl⁻-ion tot 3,4-DCB (3,4-dichloorbut-1-een).$$, 'inline'),
  ('9af2da39-e8f9-41ac-bf06-f9d9a523ea0e', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$structuurisomeren van het chlorinium-ion$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context3.png$$,
   $$In stap 1 van mechanisme 1 wordt een cyclisch chlorinium-ion gevormd. Van dit ion kunnen ook twee niet-cyclische structuurisomeren worden gevormd. Op de uitwerkbijlage is de Lewisstructuur van een niet-cyclische structuurisomeer weergegeven, dit is structuurisomeer 1. De andere niet-cyclische structuurisomeer is structuurisomeer 2. Van dit deeltje kunnen twee grensstructuren worden gegeven. Deze grensstructuren zijn op de uitwerkbijlage onvolledig weergegeven. In beide grensstructuren heeft telkens één C-atoom geen volledig oktet. Met behulp van de grensstructuren van structuurisomeer 2 kan worden verklaard dat in stap 2 behalve 3,4-DCB ook 1,4-DCB (1,4-dichloorbut-2-een) wordt gevormd.$$, 'inline'),
  ('0428f4ce-a22e-44c0-b73d-957261a8ca61', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$cis- en trans-1,4-DCB; voorgesteld mechanisme 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context4.png$$,
   $$Van het gevormde 1,4-DCB bestaan twee stereo-isomeren, namelijk cis-1,4-DCB en trans-1,4-DCB. Een leerling doet een voorstel voor het mechanisme voor het ontstaan van 1,4-DCB. Dit voorstel is in mechanisme 2 weergegeven.$$, 'inline'),
  ('64804e08-fb5f-4504-acd3-6638e3c6d8cc', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$mechanisme 2 — voorgesteld mechanisme voor de vorming van 1,4-DCB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context5.png$$,
   $$mechanisme 2: uit buta-1,3-dieen en Cl₂ ontstaat eerst een tussenproduct met een positief geladen C3-atoom (vrij draaibaar rond de C2–C3-as) en een Cl⁻-ion; aanval van dit Cl⁻-ion op C4 levert vervolgens cis-1,4-DCB óf trans-1,4-DCB.$$, 'inline'),
  ('2ccb2bbe-4fa6-43f2-8e1f-504e051274d9', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$waargenomen cis/trans-verhouding van 1,4-DCB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context6.png$$,
   $$Het blijkt dat het gevormde 1,4-DCB voor 19% uit de cis-vorm en voor 81% uit de trans-vorm bestaat.$$, 'inline'),
  ('1d45c968-143f-45a8-8ba4-cbcce13a1612', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$blokschema-context en evenwicht 1 in reactor R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context7.png$$,
   $$Op de uitwerkbijlage bij vraag 10 is het onvolledige blokschema van de productie van chloropreen weergegeven. In reactor 1 (R1) reageert buta-1,3-dieen met chloor. Het mengsel van 1,4-DCB en 3,4-DCB wordt na een scheidingsstap (S1) als vloeistofmengsel naar reactor 2 (R2) gevoerd. In R2 treedt evenwicht 1 op: 1,4-DCB ⇌ 3,4-DCB (evenwicht 1).$$, 'inline'),
  ('489ffd95-7d5b-4c23-8fde-a1c3a88de57d', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$temperatuur en kookpunten in reactor R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context8.png$$,
   $$De temperatuur in R2 ligt tussen 125 °C en 150 °C. De temperatuur is zo gekozen dat eenvoudig een zo hoog mogelijke opbrengst aan 3,4-DCB kan worden bereikt. Bij de druk in R2 is het kookpunt van 3,4-DCB 119 °C. De kookpunten van cis-1,4-DCB en trans-1,4-DCB liggen boven 152 °C.$$, 'inline'),
  ('e6f9d83d-51d4-4fd8-926a-df9aa3ef60d2', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$reactie van 3,4-DCB met natronloog in reactor R3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context9.png$$,
   $$In reactor 3 (R3) reageert ten slotte 3,4-DCB met natronloog tot chloropreen en een oplossing van natriumchloride. Op de uitwerkbijlage is het mechanisme van deze reactie onvolledig weergegeven.$$, 'inline'),
  ('f4160f50-ada0-4b7e-8648-4fac54717d34', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$samenvatting van het gehele productieproces (R1, S1, R2, S2, R3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context10.png$$,
   $$Het gehele productieproces is hieronder samengevat. Chloor en buta-1,3-dieen worden als gas in R1 geleid, waar 3,4-DCB en 1,4-DCB en nevenproducten worden gevormd. De omzetting van chloor en buta-1,3-dieen in R1 is niet volledig. Het mengsel afkomstig uit R1 is vloeibaar en wordt naar scheidingsruimte 1 (S1) geleid. In S1 wordt stikstof door het mengsel geblazen waardoor het ongereageerde chloor en buta-1,3-dieen uit de vloeistofstroom worden verwijderd. Het gasmengsel van stikstof, chloor en buta-1,3-dieen wordt boven uit S1 teruggeleid naar R1. Om ophoping van stikstof in het systeem te voorkomen wordt een deel van deze recycle-stroom afgetapt. De vloeistofstroom uit S1 wordt naar R2 geleid. In R2 wordt 1,4-DCB onvolledig omgezet tot 3,4-DCB. Uit R2 komen twee stofstromen. De ene stroom, met uitsluitend 3,4-DCB, wordt doorgevoerd naar R3. De andere stroom uit R2 bevat 1,4-DCB en de nevenproducten. Deze stroom wordt doorgevoerd naar een destilleerkolom (S2) waar het 1,4-DCB wordt afgescheiden en teruggeleid naar R2. De nevenproducten worden als vloeistofstroom afgevoerd. In R3 reageert ten slotte 3,4-DCB met een overmaat natronloog tot chloropreen en een oplossing van natriumchloride. Het chloropreen verlaat R3 als gasstroom.$$, 'inline'),
  ('e70f850e-71d8-40bb-b35f-25beeb09f9f6', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$rendementen en molair volume voor de berekening$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context11.png$$,
   $$Het rendement van de omzetting van buta-1,3-dieen tot 3,4-DCB in R1 en R2 bedraagt in totaal 70%. Het rendement van de omzetting van 3,4-DCB tot chloropreen in R3 bedraagt 93%. Het molair volume van een gas onder de heersende omstandigheden is 2,45·10⁻² m³ mol⁻¹.$$, 'inline'),
  ('3839748d-7568-40dc-9940-b4ff2f3f6c28', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$uitwerkbijlage vraag 6 — structuurisomeren 1 en 2 van het chlorinium-ion$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context12.png$$,
   $$structuurisomeer 1 (Lewisstructuur, gegeven): H₂C=CH–CH(⁺)–CH₂–Cl, met een positieve formele lading op het derde C-atoom. structuurisomeer 2 (onvolledig, aan te vullen): twee grensstructuren van een deeltje met de keten H₂C=CH–CH–CH₂, waarbij het Cl-atoom en de ontbrekende elektronenparen en formele ladingen nog moeten worden ingevuld; in beide grensstructuren heeft één C-atoom geen volledig oktet.$$, 'uitwerkbijlage'),
  ('84224d6e-3052-458c-9661-9d8eeacbdac6', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$uitwerkbijlage vraag 9 — mechanisme vorming chloropreen uit 3,4-DCB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context13.png$$,
   $$Onvolledig weergegeven reactie: 3,4-DCB (H₂C=CH–CHCl–CH₂Cl, met niet-bindende elektronenparen op de Cl-atomen) reageert met OH⁻ tot chloropreen (H–C=C–C=C–H met één Cl-atoom) en H₂O, plus een niet nader aangeduid derde product (aangegeven met stippellijn).$$, 'uitwerkbijlage'),
  ('9301e54f-a4e8-41c1-b436-20b7c87d4a28', '084bf292-bb80-42f8-ad39-3e70997d2d0b', $$uitwerkbijlage vraag 10 — blokschema productieproces (R1, S1, R2, R3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-context14.png$$,
   $$Onvolledig blokschema: een stroom met de cijfers 1,2 (buta-1,3-dieen, chloor) gaat naar R1; vanuit R1 gaat een stroom met de cijfers 1,2,4,5,8,9 naar S1; een aparte stroom met cijfer 9 komt ook in S1; vanuit S1 gaat een stroom naar R2; vanuit R2 gaat een stroom naar R3. De destilleerkolom S2 en enkele pijlen en stofnummers ontbreken nog en moeten worden getekend/genoteerd.$$, 'uitwerkbijlage'),
  ('a27c67d0-4e7d-4829-8dbd-5dc02841df78', '3febb6f3-9744-4cd9-8644-212e936adebf', $$mRNA-volgorde van het HFE-gen (met en zonder mutatie)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context1.png$$,
   $$Hemochromatose of ijzerstapeling is een erfelijke ziekte waarbij te veel ijzerionen uit de darminhoud worden opgenomen terwijl het lichaam niet in staat is de overmaat aan ijzerionen uit te scheiden. Deze ziekte wordt vaak veroorzaakt door een mutatie in het gen dat codeert voor het eiwit HFE. HFE speelt een rol bij de opname van ijzerionen. Bij de synthese van HFE wordt in eerste instantie mRNA gevormd dat bestaat uit 2727 basen. De eerste 221 basen spelen echter geen rol bij de synthese van HFE. Het startcodon begint pas bij base nummer 222. Dit is tevens het codon voor het aminozuur met nummer 1. Hieronder is een deel van de mRNA-volgorde bij mensen zonder en mensen met hemochromatose weergegeven; de mutatie treedt op bij base nummer 1066. mensen zonder hemochromatose: ...UACGUGCCAG... (pijl bij base 1066). mensen met hemochromatose: ...UACGUACCAG...$$, 'inline'),
  ('d9371cbd-599d-471a-a21a-b123f9391801', '3febb6f3-9744-4cd9-8644-212e936adebf', $$notatie van puntmutaties met 1-lettersymbolen (voorbeeld Q86E)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context2.png$$,
   $$Met behulp van de 1-lettersymbolen van aminozuren kan men dit soort mutaties vereenvoudigd weergeven. Zo kan een mutatie waarbij op plaats 86 van een eiwit een glutaminezuur-eenheid is ingebouwd in plaats van een glutamine-eenheid, worden weergegeven als Q86E.$$, 'inline'),
  ('2f703d3e-4123-4104-8a54-6fb4b4ab5e19', '3febb6f3-9744-4cd9-8644-212e936adebf', $$binding van Fe³⁺ aan transferrine; pH-afhankelijkheid$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context3.png$$,
   $$De uit de darminhoud opgenomen ijzerionen komen in het bloed terecht. Daar worden deze ionen gebonden door het eiwit transferrine en worden zo getransporteerd naar de lever en naar de plaatsen waar de productie van rode bloedlichaampjes plaatsvindt. Het binden en afstaan van de ijzerionen door transferrine is afhankelijk van de pH. Daarbij zijn de restgroepen van de aminozuren Tyr, Asp en His betrokken. Hiernaast is schematisch weergegeven hoe een Fe³⁺-ion in een molecuul transferrine is gebonden, via twee gedeprotoneerde fenolgroepen (Tyr), een carboxylaatgroep (Asp) en de imidazoolstikstof van His. Bij de pH van bloed (7,4) zijn Fe³⁺-ionen sterk gebonden aan transferrine. Op de plaatsen in het lichaam waar transferrine de gebonden Fe³⁺-ionen moet afstaan, is de pH aanzienlijk lager. De Fe³⁺-ionen komen dan vrij uit de moleculen transferrine.$$, 'inline'),
  ('79a7abbc-9a5e-4a10-a445-d059ca61e5d8', '3febb6f3-9744-4cd9-8644-212e936adebf', $$desferrioxamine en de structuurformule van stof A$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context4.png$$,
   $$Patiënten met hemochromatose kunnen worden behandeld met desferrioxamine, een stof die in opgeloste vorm met behulp van een infuus wordt toegediend. Desferrioxamine bindt Fe³⁺. Via de nieren wordt de ontstane verbinding uitgescheiden. Een molecuul desferrioxamine ontstaat uit één molecuul ethaanzuur (E), twee moleculen butaandizuur (B) en drie moleculen van een stof A. De structuurformule van stof A is hieronder weergegeven: H₂N–(CH₂)₅–N(OH)–H.$$, 'inline'),
  ('1159ced0-bc08-4793-9102-caa7c327902f', '3febb6f3-9744-4cd9-8644-212e936adebf', $$koppelvolgorde van de bouwstenen van desferrioxamine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context5.png$$,
   $$Deze zes moleculen worden in de volgorde A – B – A – B – A – E gekoppeld. Daarbij worden alleen C–N-bindingen gevormd. Per ontstane C–N-binding wordt één molecuul water afgesplitst.$$, 'inline'),
  ('41664c57-28b1-43be-9c58-84e2f5f4b9a5', '3febb6f3-9744-4cd9-8644-212e936adebf', $$bereiding van de bufferoplossing (NaHCO₃ en HCl)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context6.png$$,
   $$Om te onderzoeken of iemand hemochromatose heeft, wordt bloedonderzoek gedaan. Voor het onderzoek is een bufferoplossing bereid. Deze oplossing is bereid door per liter achtereenvolgens 0,338 mol NaHCO₃ en 3,4·10⁻² mol waterstofchloride (HCl) op te lossen. In de uiteindelijke oplossing zijn onder andere deeltjes H₂CO₃ en HCO₃⁻ aanwezig.$$, 'inline'),
  ('95508439-8ddc-4eb3-9702-234f68e3245d', '3febb6f3-9744-4cd9-8644-212e936adebf', $$gegevens voor de berekening van de vrije ijzerbindende capaciteit CF$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-ijzerstapeling-context7.png$$,
   $$Van een patiënt wordt bloed afgenomen, waarna het bloedserum wordt afgescheiden van de rode bloedlichaampjes. Het bloedserum bevat alle transferrine. Bij het vaststellen of iemand hemochromatose heeft, is onder andere de vrije ijzerbindende capaciteit CF van belang. Dit is het aantal mol Fe³⁺ dat per liter bloedserum nog aan het transferrine kan worden gebonden. Bij gezonde mensen bevat het bloedserum gemiddeld 3,0 g transferrine per liter en is gemiddeld 30% van de bindingsplaatsen van het transferrine bezet met Fe³⁺-ionen. Per molecuul transferrine kunnen twee Fe³⁺-ionen worden gebonden. De molaire massa van transferrine is 8,0·10⁴ g mol⁻¹.$$, 'inline'),
  ('ac92b505-aa89-4be2-8446-17a02b9b86b5', '0bce5ef4-204d-4b34-aa80-302ee0b8a65b', $$suikerbatterij op basis van glucose; omzetting tot ethaanzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-suikerbatterij-context1.png$$,
   $$Een suikerbatterij maakt gebruik van glucose als energiebron. In de eerste suikerbatterij die is gemaakt, werd glucose met behulp van enzymen geöxideerd tot onder andere ethaanzuur. De totaalvergelijking van deze omzetting is hieronder weergegeven: C₆H₁₂O₆ + 2 O₂ → 2 CO₂ + 2 H₂O + 2 CH₃COOH. De maximale energie per mol glucose die in een batterij vrij kan komen, is gelijk aan de verbrandingsenergie van glucose, dat is de energie die vrijkomt bij de volledige verbranding. De vormingswarmte van glucose is −12,61·10⁵ J mol⁻¹.$$, 'inline'),
  ('b87aecc9-c0cf-4f44-baf7-df5628804df6', '0bce5ef4-204d-4b34-aa80-302ee0b8a65b', $$opstelling en (half)reacties I–III van de maltodextrine-batterij$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-suikerbatterij-context2.png$$,
   $$Een groep onderzoekers heeft een batterij ontwikkeld waarbij de polysacharide maltodextrine volledig werd omgezet tot CO₂ en H₂O. Maltodextrine is opgebouwd uit glucose-monomeereenheden en kan worden weergegeven als H–(C₆H₁₀O₅)ₙ–OH met 3 < n < 20. Voor de volledige omzetting van maltodextrine tot CO₂ en H₂O hebben de onderzoekers enzymen uit verscheidene micro-organismen gebruikt. In de figuur is de gebruikte opstelling vereenvoudigd weergegeven. Met reacties I, II en III zijn de verlopende (half)reacties bij stroomlevering schematisch aangegeven: H–(C₆H₁₀O₅)ₙ–OH wordt via reactie I (met HPi) omgezet in C₆H₁₁O₅–Pi; C₆H₁₁O₅–Pi wordt via reactie II (met H₂O) omgezet in C₅H₉O₄–Pi, CO₂ en H⁺ + e⁻; C₅H₉O₄–Pi wordt via reactie III (met H₂O) omgezet terug in C₆H₁₁O₅–Pi en HPi. Aan de andere elektrode (achter het membraan) reageren O₂, H⁺ en e⁻ tot H₂O. Door de (half)reacties I t/m III wordt de maltodextrine uiteindelijk volledig omgezet. Elektronen komen uitsluitend vrij in reactie II.$$, 'inline'),
  ('8788238e-64ae-4df9-be00-cf772a55ae15', '0bce5ef4-204d-4b34-aa80-302ee0b8a65b', $$reactie I — vorming van glucose-6-fosfaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-suikerbatterij-context3.png$$,
   $$Reactie I: maltodextrine reageert met een deeltje dat in de oplossing aanwezig is. Dit deeltje wordt in deze opgave weergegeven met H–Pi. Hierbij ontstaat onder andere glucose-6-fosfaat (C₆H₁₁O₅–Pi). De keten van maltodextrine wordt in reactie I één glucose-eenheid korter. De vergelijking van reactie I is hieronder gegeven: H–(C₆H₁₀O₅)ₙ–OH + H–Pi → C₆H₁₁O₅–Pi + H–(C₆H₁₀O₅)ₙ₋₁–OH.$$, 'inline'),
  ('7f8698b9-4829-420e-8d6e-dfabba080bb8', '0bce5ef4-204d-4b34-aa80-302ee0b8a65b', $$reactie II — omzetting tot ribulose-5-fosfaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-suikerbatterij-context4.png$$,
   $$Reactie II: in een halfreactie wordt C₆H₁₁O₅–Pi omgezet tot onder andere ribulose-5-fosfaat (C₅H₉O₄–Pi).$$, 'inline'),
  ('17590cba-8e9a-4f23-9022-dbbee5e4de23', '0bce5ef4-204d-4b34-aa80-302ee0b8a65b', $$reactie III — regeneratie van glucose-6-fosfaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-suikerbatterij-context5.png$$,
   $$Reactie III: het ontstane C₅H₉O₄–Pi wordt weer omgezet tot C₆H₁₁O₅–Pi en H–Pi. Het C₅H₉O₄–Pi is hierbij de enige bron van koolstofatomen.$$, 'inline'),
  ('edf0b517-1ccf-4ea3-9ce8-a12b3c1cd286', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$Marquis-reagens: bereiding uit zwavelzuur- en methanaloplossing$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context1.png$$,
   $$De politie controleert regelmatig op bezit van harddrugs. Voor een snelle test is onder andere het Marquis-reagens ontwikkeld. Aan een zakje van dit reagens voegt men wat van het te onderzoeken monster toe. Als het monster drugs bevat, ontstaat een kenmerkende kleur. Het Marquis-reagens wordt bereid door oplossingen van zwavelzuur en methanal te mengen in de volumeverhouding 20 : 1,0. In de tabel staan enkele gegevens van de gebruikte oplossingen: zwavelzuur-oplossing — gehalte 98 massa%, dichtheid 1,84 g mL⁻¹; methanal-oplossing — gehalte 37 massa%, dichtheid 1,09 g mL⁻¹.$$, 'inline'),
  ('48525aba-3d55-4a55-b152-dedd8f958230', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$figuur — berberine, morfine en heroïne (afgeleid van tyrosine)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context2.png$$,
   $$Marquis-reagens wordt voornamelijk gebruikt om alkaloïden van elkaar te onderscheiden. Veel alkaloïden zijn afgeleid van een aminozuur. In de figuur zijn drie alkaloïden weergegeven die zijn ontstaan uit het aminozuur tyrosine: berberine, morfine en heroïne. De oorspronkelijke structuur van tyrosine is nog in de drie structuren te herkennen. Op de uitwerkbijlage is de structuurformule van morfine nogmaals weergegeven.$$, 'inline'),
  ('ece3ae29-4ccc-47a7-a612-047a14084836', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$voorwaarde voor basisch gedrag van alkaloïden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context3.png$$,
   $$In alle alkaloïden zijn stikstofatomen aanwezig. Als zo'n stikstofatoom een niet-bindend elektronenpaar heeft, kan het atoom een H⁺-ion binden waardoor het alkaloïde als base kan reageren.$$, 'inline'),
  ('08d01938-693c-4dfe-bab3-aefc9807f31d', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$onderscheid morfine/heroïne via NO₂-substitutie en waterstofbrug$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context4.png$$,
   $$Heroïne en morfine geven beide met Marquis-reagens een paars-violette kleur. Om toch onderscheid te kunnen maken tussen deze twee stoffen, voert men nog een ander experiment uit. Er treedt nu een reactie op, waarbij in moleculen van beide stoffen het H-atoom op C1 wordt vervangen door een NO₂-groep. Morfine geeft nu een oranje kleur en heroïne een gele kleur. De oorzaak van dit kleurverschil wordt toegeschreven aan het optreden van een intramoleculaire interactie die bij morfine wel en bij heroïne niet optreedt. Deze interactie kan worden opgevat als een waterstofbrug waarbij een O-atoom van de NO₂-groep is betrokken. Op de uitwerkbijlage is een deel van het molecuul van de omgezette morfine weergegeven. Hierbij zijn de bindende elektronenparen in de NO₂-groep onvolledig weergegeven.$$, 'inline'),
  ('6568e22c-e72f-4b79-b13a-941dc9cd79da', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$uitwerkbijlage vraag 21 — structuurformule van morfine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context5.png$$,
   $$Volledige structuurformule van morfine (met genummerde ringposities C1–C6, een N–CH₃-groep en twee OH-groepen), te gebruiken om het deel dat van tyrosine afkomstig is te omcirkelen.$$, 'uitwerkbijlage'),
  ('08e41130-e7b2-4480-bcc4-72bf2169c1ee', 'a029956d-562e-4ab2-8453-bb906cf1bfe0', $$uitwerkbijlage vraag 23 — NO₂-groep op omgezette morfine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-marquis-reagens-voor-alkaloiden-context6.png$$,
   $$Onvolledig weergegeven fragment van de omgezette morfine: een benzeenring (met posities 1 t/m 6) met een NO₂-groep op C1 (bindende elektronenparen nog niet volledig getekend) en een OH-groep op C2.$$, 'uitwerkbijlage');

