  ('35cb8a49-63dd-4e1c-9118-e1b40987c89e', '084bf292-bb80-42f8-ad39-3e70997d2d0b', 7,
   '[{"domain": "Reacties", "subdomain": "Reactiekinetiek"}]'::jsonb,
   '["reactiemechanisme", "cis-trans isomerie", "vrije draaibaarheid", "stereo-isomeren", "carbokation"]'::jsonb,
   $$Verklaren waarom een voorgesteld mechanisme de waargenomen cis/trans-verhouding niet kan verklaren$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-i-chloropreenfabriek-vraag7.png$$, $$Leg uit dat mechanisme 2 geen verklaring biedt voor de waargenomen verhouding van de stereo-isomeren bij de vorming van 1,4-DCB uit chloor en buta-1,3-dieen.$$, array['0428f4ce-a22e-44c0-b73d-957261a8ca61', '64804e08-fb5f-4504-acd3-6638e3c6d8cc', '2ccb2bbe-4fa6-43f2-8e1f-504e051274d9']::uuid[]),
  ('8c4e4952-f7d7-49ac-ab03-dddc33d119d4', '084bf292-bb80-42f8-ad39-3e70997d2d0b', 8,
